package be.schaubroeck.lpb.rkm.rekenmotor.planningsuren;

import be.schaubroeck.lpb.rkm.rekenmotor.PlanningsurenCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.UitzPerUurModus;
import be.schaubroeck.lpb.rkm.rekenmotor.util.AantalRszDagen;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvattingUitzPerUur;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Dienstverband;
import be.schaubroeck.lpb.tools.enumtypes.Maandverwerking;
import be.schaubroeck.temporal.interval.LocalDateInterval;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class UitzonderlijkPerUurNew implements UitzonderlijkPerUur {


    private final RkmCoreHrConfiguratieManager hrConfiguratieManager;

    private final RekenTijd rekenTijd;

    public UitzonderlijkPerUurNew(
            RkmCoreHrConfiguratieManager hrConfiguratieManager, RekenTijd rekenTijd) {
        this.hrConfiguratieManager = hrConfiguratieManager;
        this.rekenTijd = rekenTijd;
    }

    public UitzPerUurModus bepaal(PersoonsDataManager dataManager, Opdracht opdracht, RekenTijd rekenTijd) {
        PlanningsurenCoreHrConfiguratie coreHrConfiguratie = hrConfiguratieManager.getPlanningsurenCoreHrConfiguratie(opdracht, rekenTijd);
        boolean heeftDertigsten = opdracht.getOpperSlices().stream().anyMatch(x -> x.getWeddeBerekening().getOmzettingLoonMaandNaarDag() == Maandverwerking.DERTIGSTEN);
        boolean isUitzonderlijkPerUur =
                opdracht.getOpperSlices().stream().anyMatch(x -> x.getWeddeBerekening().getOmzettingLoonMaandNaarDag() == Maandverwerking.PLANNINGSUREN);
        List<NlpPrestatie> prestaties = dataManager.findPrestaties(opdracht, rekenTijd.eindDatum);
        if (!isUitzonderlijkPerUur) {
            isUitzonderlijkPerUur = coreHrConfiguratie.isUitzonderlijkePlanningsuren() && heeftDertigsten &&
                    prestaties.stream().anyMatch(x -> isCodeUizonderlijkPerUur(x, coreHrConfiguratie));
        }
        UitzPerUurModus uitzPerUurModus = UitzPerUurModus.GEEN;
        if (isUitzonderlijkPerUur) {
            boolean isUitzPerUurMetLangdurigAfwezigheid = prestaties.stream().anyMatch(x -> isLangdurigeAfwezigheid(x.getCode(), x.getExtensie(), coreHrConfiguratie));
            if (isUitzPerUurMetLangdurigAfwezigheid) {
                uitzPerUurModus = UitzPerUurModus.UITZ_PER_UUR_LANGDURIG_AFWEZIGHEID_NEW;
            } else {
                uitzPerUurModus = UitzPerUurModus.UIITZONDERLIJK_PER_UUR_NEW;
            }
        }
        return uitzPerUurModus;
    }

    private boolean isCodeUizonderlijkPerUur(NlpPrestatie prestatie, PlanningsurenCoreHrConfiguratie configuratie) {
        boolean dagOfKalenderCode = prestatie.getAard().equals(AardKodeExt.D_KODE_EXT.getCode()) || prestatie.getAard().equals(AardKodeExt.K_KODE_EXT.getCode());
        boolean prestatieUitzPerUur = configuratie.getUitzonderlijkeAkes().stream().anyMatch(ake -> matches(prestatie.getCode(), prestatie.getExtensie(), ake));
        return dagOfKalenderCode && prestatieUitzPerUur;
    }

    public boolean isLangdurigeAfwezigheid(Integer code, Integer extensie, PlanningsurenCoreHrConfiguratie configuratie) {
        return configuratie.getLangdurigeAkes().stream().anyMatch(ake -> matches(code, extensie, ake));
    }

    private boolean matches(Integer code, Integer extensie, AardKodeExtensie ake) {
        return code.equals(ake.getCode()) && extensie.equals(ake.getExtensie());
    }

    public boolean excluderenInNoemer(Integer code, Integer extensie) {
        return false;
    }

    public boolean includerenDagCode(AardKodeExtensie looncode) {
        return true;
    }


    public boolean includerenKalenderCode(AardKodeExtensie looncode) {
        return true;
    }

    public boolean isLangdurigeAfwezigheid(Opdracht opdracht, Integer code, Integer extensie) {
        PlanningsurenCoreHrConfiguratie coreHrConfiguratie = hrConfiguratieManager.getPlanningsurenCoreHrConfiguratie(opdracht, rekenTijd);
        return isLangdurigeAfwezigheid(code, extensie, coreHrConfiguratie);

    }

    @Override
    public void bepaalTotaalAantalUren(RekenContext opdrachtContext, Opdracht opdracht) {
        UitzPerUurModus uitzPerUurModus = opdrachtContext.getUnchecked(RekenChainKey.UITZONDERLIJK_PER_UUR_KEY);
        if (uitzPerUurModus != UitzPerUurModus.GEEN) {
            RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
            BigDecimal totaalAantalUren = BigDecimal.ZERO;
            for (Opper opper : opdracht.getOpperSlices()) {
                PrestatieSamenvattingUitzPerUur samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper);
                totaalAantalUren = totaalAantalUren.add(samenvatting.getTotaalAantalUren());
            }
            BigDecimal fictieveUrenCaseIndienstOfUitdienst = bepaalFictieveUrenCaseIndienstOfUitdienstUitzPerUur(opdracht, rekenTijd);
            totaalAantalUren = totaalAantalUren.add(fictieveUrenCaseIndienstOfUitdienst);

            for (Opper opper : opdracht.getOpperSlices()) {
                PrestatieSamenvattingUitzPerUur samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper);
                samenvatting.setTotaalAantalUren(totaalAantalUren);
            }
        }
    }

    @Override
    public boolean onderzoekBezoldigdePrestatiesAanwezig(
            Opdracht opdracht, List<NlpPrestatie> prestaties, LoonCodeManager loonCodeManager, UitzPerUurModus uitzPerUurModus) {
        return UitzonderlijkPerUurBezoldigdePrestatiesOnderzoek.onderzoek(opdracht, prestaties, loonCodeManager, uitzPerUurModus, this);
    }


    private BigDecimal bepaalFictieveUrenCaseIndienstOfUitdienstUitzPerUur(Opdracht opdracht, RekenTijd rekenTijd) {
        BigDecimal totaalAantalUren = BigDecimal.ZERO;
        Set<Opper> oppersInDienst =
                opdracht.getOpperSlices().stream().filter(x -> x.getRszppo().getDienstverband() == Dienstverband.JA).collect(Collectors.toSet());

        Opper vroegsteOpper = RekenTools.getEersteGegevens(oppersInDienst);
        if (vroegsteOpper != null && !vroegsteOpper.getLocalDateInterval().contains(rekenTijd.beginDatum)) {
            LocalDateInterval fictiefBeginInterval = new LocalDateInterval(rekenTijd.beginDatum, vroegsteOpper.getActualFrom().minusDays(1));
            totaalAantalUren = totaalAantalUren.add(getFictieveUren(vroegsteOpper, fictiefBeginInterval));
        }
        Opper laatsteOpper = RekenTools.getLaatsteGegevens(oppersInDienst);
        if (laatsteOpper != null && !laatsteOpper.getLocalDateInterval().contains(rekenTijd.eindDatum)) {
            LocalDateInterval fictiefEindInterval = new LocalDateInterval(laatsteOpper.getActualTo().plusDays(1), rekenTijd.eindDatum);
            totaalAantalUren = totaalAantalUren.add(getFictieveUren(laatsteOpper, fictiefEindInterval));
        }
        return totaalAantalUren;
    }

    private static BigDecimal getFictieveUren(Opper opper, LocalDateInterval nietGeverkteInterval) {
        BigDecimal aanstelling = opper.getRszppo().getAanstelling();
        int rszDagenStelsel = opper.getWeddeBerekening().getRszDagenStelsel();
        BigDecimal urenPerDag = aanstelling.divide(new BigDecimal(rszDagenStelsel), 2, RoundingMode.HALF_UP);
        BigDecimal teberekenenDagen = AantalRszDagen.inInterval(nietGeverkteInterval, rszDagenStelsel);
        return teberekenenDagen.multiply(urenPerDag);
    }


}
